    65→        queryFn: ({queryKey}) => getNotificationsCount(queryKey[1]),
    66→        enabled: !!authData?.access_token,
    67→        staleTime: 1000 * 60 * 60,
    68→        cacheTime: 1000 * 60 * 60,
    69→    })
    70→    
    71→    //hook for realtime notifications
    72→    useEffect(() =>{
    73→        if(!userData) return;
    74→
    75→        const channel = supabase
    76→        .channel('notifications')
    77→        .on('postgres_changes',
    78→        {event: 'INSERT', schema: 'public', table: 'notifications', filter: `receiver_id=eq.${userData?.userData?.[0]?.id}`},
    79→        (payload) => {
    80→            console.log('new notification:', payload)
    81→            queryClient.setQueryData(['notifcounts', authData?.user?.id], (old) => ({count: (old?.count ? old?.count : 0) + 1}));
    82→        }
    83→    )
    84→    .subscribe();
    85→
    86→    return () => {
    87→        supabase.removeChannel(channel);
    88→    }
    89→
    90→    },[userData])
    91→    
    92→
    93→    // useEffect(() => {
    94→    //     console.log(userData?.userData?.[0].id);
    95→    // }, [userData])
    96→
    97→    const signOut = async() =>{
    98→        await supabase.auth.signOut();
    99→        queryClient.setQueryData(['authsession'], null)
   100→        queryClient.clear();
   101→
   102→    }
   103→
   104→    const requireAuth = (callback) => {
   105→        if(authData){
   106→            callback();
   107→        } else {
   108→            openAuthModal();
   109→        }
   110→    }
   111→
   112→    const value = {
   113→        session: authData,
   114→        user: userData,
   115→        loading: loading,
   116→        isLoading: isLoading,
   117→        notifCount: notifCount?.count,
   118→        signOut,
   119→        showAuthModal,
   120→        openAuthModal,
   121→        closeAuthModal,
   122→        requireAuth
   123→    }
   124→    return <AuthContext.Provider value={value}>
   125→        {children}
   126→    </AuthContext.Provider>
   127→}

